INSERT INTO "books" ("id", "user_id", "title", "category", "status", "cover", "cover_image", "description", "outline", "volumes", "word_count", "chapter_count", "created_at", "updated_at", "outline_analysis", "outline_characters", "outline_world_building") VALUES ('ac9698c2-d0e8-4d82-afd7-f70c3f5b183a', '1b98fd5d-a7f0-4053-8719-ec1b0e3e8c3d', '阴差笔录', '悬疑', '草稿', 'default', NULL, '普通殡仪馆化妆师谢峰，偶然得到一卷失传的阴差笔录，从此能看见阴阳两界的隐秘。游走在生者与亡魂之间，他一边解决纠缠人间的执念凶煞，一边寻找自己身世的秘密，逐渐揭开阴阳两界尘封千年的阴谋。', '[大纲] 第一卷总大纲; [细纲] 第一章 殡仪馆的焦尸; [细纲] 第二章 第一缕阴气; [细纲] 第三章 小区红衣女; [细纲] 第四章 老馆长的委托', '[{"id":"df12e0f7-59be-4af0-acb0-224e55c99afd","title":"第一卷：阴局初开","chapters":[],"sortOrder":1}]'::jsonb, 2657, 1, '2026-06-08 13:52:35.68777+08', '2026-06-08 13:53:48.017+08', NULL, '[]'::jsonb, NULL);

