INSERT INTO "outlines" ("id", "book_id", "content", "created_at", "updated_at", "user_id") VALUES ('7c85c69b-aab2-4713-a619-48d32a0fe7b4', '55c50f4a-0d03-4c62-bc43-3c9245b0a9ed', '[{"type":"大纲","title":"第一卷：阴阳初开（第1-10章）","content":"谢峰意外获得阴阳眼能力，从恐惧逃避到初步接受。主要事件：1. 意外获得阴阳眼 2. 初遇灵异事件 3. 结识陈老 4. 学习基础能力 5. 解决第一个灵异案件"},{"type":"细纲","title":"第1章：午夜惊魂","content":"谢峰加班到深夜，回家路上在十字路口看到不该看到的东西。惊慌失措跑回家，发现自己的眼睛能看到常人看不到的阴影。整夜未眠，第二天上班精神恍惚。"},{"type":"细纲","title":"第2章：玉佩的秘密","content":"谢峰整理爷爷遗物时发现祖传玉佩，佩戴后阴阳眼能力增强，能看到更多细节。同时开始频繁看到公司里的异常现象。"},{"type":"细纲","title":"第3章：同事的异常","content":"谢峰发现同事林雨薇身上有淡淡的黑气，询问后得知她最近总是做噩梦。谢峰开始怀疑这与灵异有关。"},{"type":"细纲","title":"第4章：古董店奇遇","content":"谢峰陪林雨薇去她家古董店，遇到店主陈老。陈老一眼看出谢峰的不同，主动搭话并暗示知晓阴阳眼之事。"},{"type":"细纲","title":"第5章：初识灵异世界","content":"陈老向谢峰解释阴阳眼的由来和都市灵异的基本规则。谢峰得知自己不是唯一有特殊能力的人，都市中隐藏着许多灵异存在。"},{"type":"细纲","title":"第6章：第一个案件","content":"公司女卫生间传出奇怪声音，多名女同事反映看到白影。谢峰用阴阳眼调查，发现是一个游魂在寻找丢失的戒指。"},{"type":"细纲","title":"第7章：帮助游魂","content":"谢峰在陈老指导下学习与灵体沟通，帮助游魂找到戒指并完成心愿。游魂感激离开，谢峰第一次成功解决灵异事件。"},{"type":"细纲","title":"第8章：能力觉醒","content":"通过实践，谢峰的阴阳眼能力开始进化，能分辨灵体善恶和强度。陈老赠予镇魂铃，教导基础防身技巧。"},{"type":"细纲","title":"第9章：林雨薇的信任","content":"林雨薇发现谢峰的异常，谢峰犹豫后坦白部分真相。林雨薇没有害怕反而表示支持，两人关系拉近。"},{"type":"细纲","title":"第10章：新的委托","content":"陈老介绍第一个正式委托：调查一栋老式公寓楼的灵异现象。谢峰决定接受挑战，正式踏入都市灵异的世界。"},{"type":"大纲","title":"第二卷：灵异侦探（第11-20章）","content":"谢峰开始接受各种灵异委托，能力快速成长。结识更多灵异界人士，逐渐揭开自己家族的历史秘密。"},{"type":"大纲","title":"第三卷：都市传说（第21-30章）","content":"调查城市中的多个都市传说，发现这些传说背后都有真实灵异事件。与强大恶灵对抗，谢峰的能力达到新高度。"},{"type":"大纲","title":"第四卷：百年秘密（第31-40章）","content":"完全揭开谢峰家族百年秘密，发现阴阳眼的真正来源。面对家族宿敌的威胁，谢峰必须做出选择。"},{"type":"大纲","title":"第五卷：都市守护者（第41-50章）","content":"谢峰成为都市灵异的守护者，建立自己的团队。面对大规模灵异事件，保护城市安全。最终找到平衡阴阳的方法。"}]', '2026-06-08 13:19:44.173821+08', '2026-06-08 13:19:44.173821+08', 'default');
INSERT INTO "outlines" ("id", "book_id", "content", "created_at", "updated_at", "user_id") VALUES ('c171848d-7d7a-4111-909b-b1086db2ef26', 'ac9698c2-d0e8-4d82-afd7-f70c3f5b183a', '[{"type":"大纲","title":"第一卷总大纲","content":"谢峰在殡仪馆工作时遇到一具来历不明的焦尸，意外得到藏在尸身中的阴差笔录，开启阴差传承，接连遇到小区闹鬼、学校凶灵等小型灵异事件，初步掌握阴差笔录的能力，发现自己的身世和消失的阴差一脉有关，最终引出第一个大反派，揭开本地阴门被灭的真相。"},{"type":"细纲","title":"第一章 殡仪馆的焦尸","content":"雨夜，谢峰值班，送来一具无主的焦尸，整容时发现尸体腹腔藏着一卷泛黄的笔录，打开后看到了关于阴差的记载，当晚殡仪馆停尸间出现异常，冷藏柜自动打开，有黑影在走廊走动，谢峰发现自己能看到笔录上隐形的文字，触发主线。"},{"type":"细纲","title":"第二章 第一缕阴气","content":"谢峰按照笔录上的入门方法炼化阴气，发现焦尸的怨气不散，停尸间闹鬼越来越严重，老馆长发现异常，给谢峰讲了三十年前殡仪馆的旧事，暗示这里不止一只脏东西。"},{"type":"细纲","title":"第三章 小区红衣女","content":"谢峰请假回家，发现租住的小区最近经常有人坠楼，邻居说看到红衣女人在楼顶走，谢峰夜里蹲守，遇到邪祟，第一次用阴差的方法制服游魂，知道了坠楼的真相。"},{"type":"细纲","title":"第四章 老馆长的委托","content":"老馆长找到谢峰，说之前殡仪馆失踪了两个学徒，希望谢峰帮忙查查，谢峰在旧停尸房找到当年的日记，发现三十年前就有人在找阴差笔录。"}]', '2026-06-08 13:52:58.83785+08', '2026-06-08 13:52:58.83785+08', 'default');
INSERT INTO "outlines" ("id", "book_id", "content", "created_at", "updated_at", "user_id") VALUES ('d81c587d-c80e-4e17-a947-c92b3df3d0ef', '2b107f78-9725-4d8f-a7d1-600e57292609', '[{"type":"大纲","title":"第一卷大纲","content":"主角林砚毕业后走投无路，回到爷爷留下的老招待所继承家业，发现了爷爷留下的阴阳簿和阴差规则，第一个深夜客人上门，触发第一个灵异事件，主角逐渐适应阴差身份，同时发现爷爷的死不对劲，一步步挖出几十年前林家招待所的旧案，最终揭开第一卷的秘密，主角正式接下阴差的位置，等待后续的客人和故事。"},{"type":"细纲","title":"第一章：午夜开门","content":"林砚到招待所收拾，翻看爷爷留下的遗物，发现了阴阳簿和写着四条铁则的纸条，不信邪的他没当回事，到了午夜十二点，前门响起敲门声，林砚准备开门的时候突然想起爷爷的警告，犹豫之后开了后门，第一个阴客人上门，留下了奇怪的纸钱，林砚发现不对劲，悬念留下。"},{"type":"细纲","title":"第二章：白纸条","content":"天亮后林砚发现昨天客人留下的纸钱真的能烧，才相信爷爷说的是真的，登记的时候发现阴阳簿能自动浮现客人的信息，知道对方是三天前在国道出车祸的女人，有个孩子留在城里，林砚按照规则帮她办完手续，女人走后留下一张白纸条，上面居然浮现了孩子的住址。"},{"type":"细纲","title":"第三章：未竟的心愿","content":"林砚犹豫要不要插手阳间事，最终还是按地址找到了女人的孩子，发现孩子被后妈虐待，林砚帮女人完成了送遗物的心愿，第一次完成阴差任务，阴阳簿解锁了半页爷爷留下的批注，提到了三十年前的一个逃兵客人。"},{"type":"细纲","title":"第四章：第三个人","content":"林砚开始留意爷爷留下的东西，发现招待所的住客登记本里，有好几页被撕掉了，对应就是三十年前那段时间，同时接连来了两个奇怪的客人，都提到了当年那个逃兵，说他当年带走了一样重要的东西。"},{"type":"细纲","title":"第五章：破戒","content":"一个凶魂找上门，要找当年逃兵留下的东西，大开杀戒，林砚为了保护附近路过的活人，被迫破了第三条铁则，强行留住了凶魂，阴阳颠倒开始，招待所变成阴境，林砚靠着阴阳簿才勉强压制住凶魂，发现爷爷的房间里有个暗格。"},{"type":"细纲","title":"第六章：旧照片","content":"暗格里翻出三十年前的老照片，照片上除了爷爷和那个逃兵，还有一个穿警服的人，脸被划掉了，旁边写着一个地址在县城，同时林砚发现爷爷的死亡证明有问题，法医鉴定的死因和尸体表现出来的不对，爷爷其实是被杀的。"},{"type":"细纲","title":"第一卷结局：客人回来了","content":"林砚准备去县城查线索，当天晚上，后门响起敲门声，一个穿着旧军装的男人站在外面，说要住店，他就是三十年前消失的那个逃兵。"}]', '2026-06-08 14:10:55.791215+08', '2026-06-08 14:10:55.791215+08', 'default');

