INSERT INTO "user_settings" ("id", "book_id", "data", "created_at", "updated_at") VALUES ('6b1789d0-779d-4b9f-80c8-caa785007901', 'ac9698c2-d0e8-4d82-afd7-f70c3f5b183a', '[{"id":"94bf42f9-0f2a-44bb-94d9-26ff3c92fbb3","name":"谢峰","type":"主角","description":"二十五岁，市殡仪馆实习化妆师，父母早亡，性格沉稳冷静，天生阴阳眼，从小就能看见常人看不见的东西，为了不被当成疯子一直刻意隐藏，对生死看淡，入行后见惯了各种离奇死亡的遗体，心理素质远超常人。"},{"id":"a4dd579b-7296-4781-bf22-70d167fa26b4","name":"阴差笔录","type":"金手指","description":"一卷泛黄的古旧笔录，记载着阴差引渡亡魂的口诀、处理凶煞厉鬼的方法，还有历代阴差留下的案件记录，得到它之后谢峰能沟通阴阳，开启阴差传承，逐渐掌握阴阳术法。"},{"id":"b653f272-dc11-41c9-bc89-f22ed853ecdd","name":"现代阴阳界","type":"世界背景","description":"现代社会科技发达，但阴阳两界的规则从未消失，枉死的亡魂会变成凶煞害人，积年的怨气会凝结成鬼域，极少数正统阴阳先生传承了下来，而阴差一脉已经消失近百年，多数人都以为阴阳之说只是传说。"},{"id":"c5d232db-5834-47b2-8030-6c7597b5ec2b","name":"化妆箱","type":"物品","description":"谢峰日常工作用的化妆箱，里面除了普通的化妆工具，后来放了阴差笔录、糯米、墨斗线等阴阳道具，是他不离身的东西。"}]'::jsonb, '2026-06-08 13:52:48.212454+08', '2026-06-08 13:52:48.212454+08');
INSERT INTO "user_settings" ("id", "book_id", "data", "created_at", "updated_at") VALUES ('a9250a21-3804-4076-a062-5902295bbd38', '2b107f78-9725-4d8f-a7d1-600e57292609', '[{"id":"c2353614-6283-4421-8605-18e3d319eaa8","name":"阳间驿路","type":"世界背景","description":"阴阳两界并非完全隔绝，凡古驿道、老渡口附近的阳间建筑，都可能成为阴魂赶路落脚的招待所，阴差需要负责看顾门户，登记魂魄身份，押解怨气过重的凶魂，避免扰了阳间人的安宁。"},{"id":"e9c0aa51-2f3b-4180-a0d9-2b174eb342fd","name":"林砚","type":"主角","description":"二十三岁，刚从大学毕业，找不到合适工作，爷爷去世后继承了位于老国道旁的林家招待所，才知道林家世代都是看守招待所的阴差，天生能见鬼。性格偏稳，不想惹事，但是被逼到头上也敢硬刚。"},{"id":"fe87f694-2aba-4770-89d0-9f8802348ff1","name":"阴阳簿","type":"金手指","description":"林家传下来的老旧线装本，能登记阴魂信息，查看阳间未了心愿，也能压制凶魂，随着完成阴差任务，会慢慢解锁更多关于林家旧案的信息。"},{"id":"a55dfbcc-9cd6-47ff-ad57-3f59bbe61421","name":"招待所铁则","type":"规则设定","description":"1. 过了十二点，不开前门开后门；2. 客人给的钱不能放阳光下，天亮必须烧掉；3. 住店的客人说什么时候走，绝对不能留；4. 不碰客人的东西，不问客人过去。一旦破戒，阴阳颠倒，阳间人也要留在这里当客人。"}]'::jsonb, '2026-06-08 14:10:35.498744+08', '2026-06-08 14:10:35.498744+08');
INSERT INTO "user_settings" ("id", "book_id", "data", "created_at", "updated_at") VALUES ('e7d70650-bbdb-4a2c-89fd-fc96c8aa80ab', '55c50f4a-0d03-4c62-bc43-3c9245b0a9ed', '[{"id":"db98b617-1fec-4834-b075-d4c4ed44b55d","name":"谢峰","type":"角色设定","description":"25岁，普通上班族，在一家广告公司做设计。性格内向谨慎，但内心善良正直。身高178cm，长相普通但眼神清澈。意外获得阴阳眼能力，能看到鬼魂和灵异现象。最初对能力感到恐惧，后来逐渐接受并学习控制。有一个隐藏身份：百年前阴阳师家族的后裔。"},{"id":"99e33bdf-9131-419e-a99e-27a246a566b7","name":"林雨薇","type":"角色设定","description":"23岁，谢峰的同事，性格开朗活泼的行政助理。对灵异事件既害怕又好奇，后来成为谢峰的第一个知情人。暗恋谢峰但不敢表白。家族是开古董店的，对古物有一定了解。"},{"id":"e403edea-3756-4500-a77f-7e4184e344f6","name":"陈老","type":"角色设定","description":"70岁，古董店老板，表面上是普通老人，实际上是隐世的道术传人。在谢峰获得阴阳眼后主动接近并指导他。知晓谢峰家族的历史秘密。"},{"id":"b8400b7b-f718-4f51-a589-aaf5217b4ac7","name":"阴阳眼能力体系","type":"世界设定","description":"1. 基础能力：能看到鬼魂、灵体、阴气流动。2. 进阶能力：分辨鬼魂善恶、感知灵异强度、短暂与灵体沟通。3. 限制：过度使用会消耗精神力，导致头痛甚至晕厥。4. 弱点：对强烈阳气或阴气集中的地方视线会模糊。"},{"id":"18f34705-7743-4118-bfe4-aaecf451788e","name":"都市灵异规则","type":"世界设定","description":"1. 鬼魂分类：游魂（无害）、怨灵（有执念）、恶鬼（有攻击性）、厉鬼（极度危险）。2. 灵异现象多发生在：医院太平间、老旧建筑、十字路口、深夜地铁站等阴气重的地方。3. 时间规律：子时（23-1点）阴气最盛，灵异现象最活跃。4. 都市传说：每个城市都有特定的灵异传说和禁忌。"},{"id":"2f50ef8a-0063-46d2-a8c4-206769e2dfb9","name":"祖传玉佩","type":"物品设定","description":"谢峰从已故爷爷遗物中找到的玉佩，青绿色，雕刻着复杂符文。是激活谢峰阴阳眼的媒介，也是家族传承的信物。佩戴时能增强阴阳眼能力，对恶灵有一定震慑作用。"},{"id":"abc7fb3d-d6bf-48e1-ba04-8f7c5f180442","name":"镇魂铃","type":"物品设定","description":"陈老赠予谢峰的法器，铜制小铃，摇动时能发出常人听不见的声音，对灵体有震慑和驱散作用。需要配合特定咒语使用。"}]'::jsonb, '2026-06-08 13:19:05.13629+08', '2026-06-08 13:19:05.13629+08');

